// src/App.js
import React, { useState, useEffect } from "react";
import Dice from "react-dice-roll";

// --- Board Image path ---
const boardImage = "/torahpoly_board.png";

// --- Red Properties ---
const schemRoyalEstates = {
  type: "property",
  name: "Schem Royal Estates",
  colorGroup: "red",
  price: 300,
  rent: { base: 60, house1: 150, house2: 350, house3: 700, hotel: 800 },
  buildCost: { house: 200, hotel: 300 },
  houses: 0,
  hotel: false,
  ownerIndex: null,
};

const schemYosephGardens = {
  type: "property",
  name: "Schem Yoseph Gardens",
  colorGroup: "red",
  price: 300,
  rent: { base: 60, house1: 150, house2: 350, house3: 700, hotel: 800 },
  buildCost: { house: 200, hotel: 300 },
  houses: 0,
  hotel: false,
  ownerIndex: null,
};

const schemDreamResorts = {
  type: "property",
  name: "Schem Dream Resorts",
  colorGroup: "red",
  price: 300,
  rent: { base: 50, house1: 100, house2: 650, house3: 750, hotel: 750 },
  buildCost: { house: 150, hotel: 250 },
  houses: 0,
  hotel: false,
  ownerIndex: null,
};

// --- Yellow Property ---
const ephraimHilltops = {
  type: "property",
  name: "Ephraim Hilltops",
  colorGroup: "yellow",
  price: 300,
  rent: { base: 50, house1: 300, house2: 400, house3: 500, hotel: 800 },
  buildCost: { house: 50, hotel: 100 },
  houses: 0,
  hotel: false,
  ownerIndex: null,
};

// --- Green Properties ---
const gushKatif = {
  type: "property",
  name: "Gush Katif",
  colorGroup: "green",
  price: 350,
  rent: { base: 60, house1: 150, house2: 350, house3: 700, hotel: 1000 },
  buildCost: { house: 150, hotel: 250 },
  houses: 0,
  hotel: false,
  ownerIndex: null,
};

const neveDekalim = {
  type: "property",
  name: "Neve Dekalim",
  colorGroup: "green",
  price: 350,
  rent: { base: 50, house1: 200, house2: 300, house3: 650, hotel: 800 },
  buildCost: { house: 150, hotel: 200 },
  houses: 0,
  hotel: false,
  ownerIndex: null,
};

const ganOr = {
  type: "property",
  name: "Gan Or",
  colorGroup: "green",
  price: 350,
  rent: { base: 50, house1: 100, house2: 300, house3: 650, hotel: 800 },
  buildCost: { house: 150, hotel: 200 },
  houses: 0,
  hotel: false,
  ownerIndex: null,
};

// --- Purple Properties ---
const jerusalemHills = {
  type: "property",
  name: "Jerusalem Hills",
  colorGroup: "purple",
  price: 200,
  rent: { base: 10, house1: 200, house2: 250, house3: 300, hotel: 400 },
  buildCost: { house: 50, hotel: 100 },
  houses: 0,
  hotel: false,
  ownerIndex: null,
};

const jerusalemHillsOrchard = {
  type: "property",
  name: "Jerusalem Hills Orchard",
  colorGroup: "purple",
  price: 220,
  rent: { base: 10, house1: 200, house2: 250, house3: 300, hotel: 400 },
  buildCost: { house: 50, hotel: 100 },
  houses: 0,
  hotel: false,
  ownerIndex: null,
};

// --- Gold Properties ---
const hevronHiTech = {
  type: "property",
  name: "Hevron Hi Tech",
  colorGroup: "gold",
  price: 300,
  rent: { base: 25, house1: 60, house2: 175, house3: 500, hotel: 600 },
  buildCost: { house: 60, hotel: 100 },
  houses: 0,
  hotel: false,
  ownerIndex: null,
};

const hevronEloneiMamre = {
  type: "property",
  name: "Hevron Elonei Mamre",
  colorGroup: "gold",
  price: 320,
  rent: { base: 30, house1: 70, house2: 200, house3: 550, hotel: 650 },
  buildCost: { house: 80, hotel: 150 },
  houses: 0,
  hotel: false,
  ownerIndex: null,
};

const hevronLuxuryCondos = {
  type: "property",
  name: "Hevron Luxury Condos",
  colorGroup: "gold",
  price: 300,
  rent: { base: 25, house1: 60, house2: 175, house3: 500, hotel: 600 },
  buildCost: { house: 60, hotel: 100 },
  houses: 0,
  hotel: false,
  ownerIndex: null,
};

// --- Board events map ---
const boardEvents = {
  1: { type: "property", card: schemRoyalEstates },
  3: { type: "property", card: schemYosephGardens },
  4: { type: "property", card: schemDreamResorts },
  7: { type: "property", card: ephraimHilltops },
  11: { type: "property", card: gushKatif },
  12: { type: "property", card: neveDekalim },
  14: { type: "property", card: ganOr },
  28: { type: "property", card: jerusalemHillsOrchard },
  29: { type: "property", card: jerusalemHills },
  35: { type: "property", card: hevronEloneiMamre },
  37: { type: "property", card: hevronLuxuryCondos },
  38: { type: "property", card: hevronHiTech },
};

// --- Build 44 board positions ---
function buildBoardPositions(refSize = 1200, margin = 100, spacesPerSide = 11) {
  const positions = [];
  const step = (refSize - 2 * margin) / (spacesPerSide - 1);

  const topY = margin;
  for (let i = 0; i < spacesPerSide; i++) positions.push({ x: Math.round(margin + i * step), y: topY });
  const rightX = refSize - margin;
  for (let i = 1; i < spacesPerSide; i++) positions.push({ x: rightX, y: Math.round(topY + i * step) });
  const bottomY = refSize - margin;
  for (let i = 1; i < spacesPerSide; i++) positions.push({ x: Math.round(rightX - i * step), y: bottomY });
  const leftX = margin;
  for (let i = 1; i < spacesPerSide - 1; i++) positions.push({ x: leftX, y: Math.round(bottomY - i * step) });

  return positions.slice(0, 44);
}

const referenceSize = 1200;
const defaultBoardPositions = buildBoardPositions(referenceSize, 100, 11);

// --- Modal Component ---
function CardModal({ card, onClose, mode, currentPlayer, updatePlayer }) {
  if (!card) return null;

  const isProperty = mode === "property";

  const handleBuyProperty = () => {
    if (currentPlayer.money < card.price) {
      alert("Not enough money to buy this property!");
      return;
    }
    updatePlayer({ ...currentPlayer, money: currentPlayer.money - card.price });
    card.ownerIndex = currentPlayer.index;
    alert(`${currentPlayer.name} bought ${card.name} for $${card.price}`);
    onClose();
  };

  return (
    <div style={modalStyles.overlay}>
      <div style={modalStyles.modal}>
        <h2>{card.name}</h2>
        {isProperty && (
          <>
            <div style={{ height: 20, backgroundColor: card.colorGroup, marginBottom: 10, borderRadius: 4 }}></div>
            <p>Price: ${card.price}</p>
            <p>Rent: ${card.rent.base}</p>
            <p>Rent with 1 House: ${card.rent.house1}</p>
            <p>Rent with 2 Houses: ${card.rent.house2}</p>
            <p>Rent with 3 Houses: ${card.rent.house3}</p>
            <p>Rent with Hotel: ${card.rent.hotel}</p>
            <p>House Cost: ${card.buildCost.house}</p>
            <p>Hotel Cost: ${card.buildCost.hotel}</p>
            <p>Owner: {card.ownerIndex !== null ? `Player ${card.ownerIndex + 1}` : "None"}</p>
            <p>Your Money: ${currentPlayer.money}</p>
            <button style={{ ...modalStyles.button, backgroundColor: "green" }} onClick={handleBuyProperty}>Buy Property</button>
            <button style={modalStyles.button} onClick={onClose}>Close</button>
          </>
        )}
      </div>
    </div>
  );
}

const modalStyles = {
  overlay: { position: "fixed", top: 0, left: 0, right: 0, bottom: 0, backgroundColor: "rgba(0,0,0,0.5)", display: "flex", justifyContent: "center", alignItems: "center", zIndex: 1000 },
  modal: { backgroundColor: "#fff", padding: 30, borderRadius: 12, minWidth: 300, maxWidth: "90%", textAlign: "center", boxShadow: "0 5px 15px rgba(0,0,0,0.3)" },
  button: { margin: "8px 5px", padding: "8px 15px", borderRadius: 6, border: "none", backgroundColor: "#007bff", color: "#fff", fontSize: 14, cursor: "pointer" },
};



// --- Part 2 ---

function App() {
  const [players, setPlayers] = useState([
    { name: "Player 1", position: 0, money: 5000, index: 0 },
    { name: "Player 2", position: 0, money: 5000, index: 1 },
  ]);
  const [currentPlayerIndex, setCurrentPlayerIndex] = useState(0);
  const [modalCard, setModalCard] = useState(null);
  const [modalMode, setModalMode] = useState(null);

  const currentPlayer = players[currentPlayerIndex];

  const rollDice = (diceValue) => {
    const newPlayers = [...players];
    let nextPos = (currentPlayer.position + diceValue) % 44;
    newPlayers[currentPlayerIndex].position = nextPos;
    setPlayers(newPlayers);

    if (boardEvents[nextPos]) {
      setModalCard(boardEvents[nextPos].card);
      setModalMode(boardEvents[nextPos].type);
    } else {
      setModalCard(null);
    }
    setCurrentPlayerIndex((currentPlayerIndex + 1) % players.length);
  };

  const updatePlayer = (updatedPlayer) => {
    const newPlayers = [...players];
    newPlayers[updatedPlayer.index] = updatedPlayer;
    setPlayers(newPlayers);
  };

  // --- Quick test buttons to jump to any property ---
  const testButtons = Object.keys(boardEvents).map((pos) => (
    <button
      key={pos}
      style={{ margin: 3, padding: "5px 10px" }}
      onClick={() => {
        setModalCard(boardEvents[pos].card);
        setModalMode(boardEvents[pos].type);
      }}
    >
      Test {boardEvents[pos].card.name}
    </button>
  ));

  return (
    <div style={{ padding: 20 }}>
      <h1>TorahPoly Game</h1>
      <div style={{ marginBottom: 10 }}>
        <Dice onRoll={rollDice} />
      </div>
      <div style={{ marginBottom: 20 }}>
        <h3>Current Player: {currentPlayer.name}</h3>
        <p>Money: ${currentPlayer.money}</p>
        <p>Position: {currentPlayer.position}</p>
      </div>

      <div style={{ display: "flex", flexWrap: "wrap" }}>
        {testButtons}
      </div>

      {modalCard && (
        <CardModal
          card={modalCard}
          onClose={() => setModalCard(null)}
          mode={modalMode}
          currentPlayer={currentPlayer}
          updatePlayer={updatePlayer}
        />
      )}

      <div style={{ marginTop: 20 }}>
        <img src={boardImage} alt="Board" style={{ maxWidth: "100%", border: "2px solid #000" }} />
      </div>
    </div>
  );
}

export default App;
